import React, { useEffect, useState } from "react";

const BillsHistory = ({ employee }) => {
  const [bills, setBills] = useState([]);
  const [filtered, setFiltered] = useState([]);

  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchBills();
  }, [employee]);

  // Fetch bills from backend
  const fetchBills = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const res = await fetch(
        `https://prasa-app-yde3.onrender.com/bills?empId=${empId}`
      );

      const data = await res.json();
      const list = Array.isArray(data) ? data : [];

      setBills(list);
      setFiltered(list);
    } catch (err) {
      console.error(err);
    }
  };

  // Filter bills
  const applyFilters = () => {
    let temp = [...bills];

    if (fromDate) {
      temp = temp.filter((b) => b.uploaded_at.substring(0, 10) >= fromDate);
    }

    if (toDate) {
      temp = temp.filter((b) => b.uploaded_at.substring(0, 10) <= toDate);
    }

    setFiltered(temp);
  };

  const resetFilters = () => {
    setFromDate("");
    setToDate("");
    setFiltered(bills);
  };

  const downloadReport = () => {
    alert("Downloading Bills Report...");
  };

  return (
    <div style={page}>
      {/* HEADER */}
      <div style={card}>
        <button style={backBtn} onClick={() => window.history.back()}>
          ←
        </button>

        <h2 style={title}>Bills History</h2>
        <p style={empInfo}>
          {employee.empName} • {employee.empId}
        </p>
      </div>

      {/* FILTER CARD */}
      <div style={filterCard}>
        <div style={filterRow}>
          <div style={filterItem}>
            <label>From Date</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
              style={dateInput}
            />
          </div>

          <div style={filterItem}>
            <label>To Date</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
              style={dateInput}
            />
          </div>

          <button style={resetBtn} onClick={resetFilters}>
            Reset
          </button>
        </div>

        <button style={applyBtn} onClick={applyFilters}>
          Apply Filters
        </button>
      </div>

      {/* TABLE */}
      <div style={tableCard}>
        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>

          <tbody>
            {filtered.length === 0 ? (
              <tr>
                <td colSpan="3" style={noData}>
                  No bills found
                </td>
              </tr>
            ) : (
              filtered.map((b) => (
                <tr key={b.id}>
                  <td>{b.uploaded_at.substring(0, 10)}</td>
                  <td>{b.file_name}</td>
                  <td>
                    <a href={b.file_path} target="_blank" rel="noreferrer">
                      View
                    </a>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* DOWNLOAD REPORT */}
      <button style={downloadBtn} onClick={downloadReport}>
        📄 Download Bills Report
      </button>
    </div>
  );
};

export default BillsHistory;

/* ---------------------- STYLES --------------------------- */

const green = "#0F9D58";

const page = {
  background: "#F1F8F2",
  minHeight: "100vh",
  padding: 20,
};

const card = {
  background: "white",
  padding: 18,
  borderRadius: 15,
  boxShadow: "0 3px 10px rgba(0,0,0,0.1)",
  marginBottom: 15,
};

const backBtn = {
  background: "#fff",
  border: `1px solid ${green}`,
  color: green,
  padding: "6px 12px",
  borderRadius: 10,
  fontSize: 18,
  cursor: "pointer",
};

const title = { fontSize: 24, color: green, fontWeight: "700" };
const empInfo = { color: "#666", marginTop: -4 };

const filterCard = {
  background: "#E8F5E9",
  padding: 20,
  borderRadius: 12,
  marginBottom: 20,
};

const filterRow = {
  display: "flex",
  justifyContent: "space-between",
  flexWrap: "wrap",
};

const filterItem = { display: "flex", flexDirection: "column", width: "30%" };

const dateInput = {
  padding: 10,
  borderRadius: 8,
  border: "1px solid #ccc",
};

const resetBtn = {
  background: green,
  color: "white",
  border: "none",
  padding: "10px 18px",
  borderRadius: 10,
  cursor: "pointer",
  marginTop: 20,
};

const applyBtn = {
  background: green,
  color: "white",
  border: "none",
  padding: "12px 18px",
  borderRadius: 10,
  cursor: "pointer",
  width: "100%",
  marginTop: 15,
  fontSize: 16,
  fontWeight: "600",
};

const tableCard = {
  background: "white",
  padding: 15,
  borderRadius: 15,
  boxShadow: "0 3px 8px rgba(0,0,0,0.08)",
};

const table = { width: "100%", borderCollapse: "collapse" };

const noData = { textAlign: "center", padding: 20, color: "#777" };

const downloadBtn = {
  background: green,
  color: "white",
  padding: "14px 20px",
  borderRadius: 12,
  fontSize: 16,
  border: "none",
  width: "100%",
  marginTop: 25,
  cursor: "pointer",
};
